// Monta o alerta a partir dos campos do errorTrigger (1 item por falha).
const wf = $json.workflow?.name || 'desconhecido'
const nd = $json.execution?.lastNodeExecuted || 'desconhecido'
const em = ($json.execution?.error?.message || 'sem mensagem').toString().slice(0, 400)
const ex = ($json.execution?.id || '').toString()
const lines = [
  '🚨 *Falha no radar de promoções*',
  'Workflow: ' + wf,
  'Nó: ' + nd,
  'Erro: ' + em,
  'Execução: ' + ex,
]
return { json: { text: lines.join('\n') } }
